import java.util.*;class SubsetSum{static boolean f(int[] a,int t,int i,int sum){if(sum==t){System.out.println(true);return true;}if(sum>t||i==a.length)return false;if(f(a,t,i+1,sum+a[i]))return true;return f(a,t,i+1,sum);}public static void main(String[] x){Scanner s=new Scanner(System.in);int n=s.nextInt();int[] a=new int[n];for(int i=0;i<n;i++)a[i]=s.nextInt();int t=s.nextInt();System.out.println(f(a,t,0,0));}}